UPDATE om_config_m
   SET max_password_fail_count = #{maxPasswordFailCount}
     , max_inactive_login_days = #{maxInactiveLoginDays}
     , allow_duplicate_login = #{allowDuplicateLogin}
     , smtp_host = #{smtpHost}
     , smtp_port = #{smtpPort}
     , smtp_username = #{smtpUsername}
     , smtp_password_enc = #{smtpPasswordEnc}
     , smtp_from_email = #{smtpFromEmail}
     , smtp_from_name = #{smtpFromName}
     , smtp_use_tls = #{smtpUseTls}
     , smtp_use_ssl = #{smtpUseSsl}
     , smtp_auth_required = #{smtpAuthRequired}
     , smtp_connection_timeout_ms = #{smtpConnectionTimeoutMs}
     , smtp_read_timeout_ms = #{smtpReadTimeoutMs}
     , smtp_write_timeout_ms = #{smtpWriteTimeoutMs}
     , updated_at = CURRENT_TIMESTAMP
 WHERE id = 1
